import java.util.ArrayList;import java.util.List;import java.util.Map;
final class MediatorPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}static final class SupportMediator{private final Map<String,List<String>>routes=Map.of("customer",List.of("agent","bot"),"agent",List.of("customer"),"bot",List.of("agent"));List<Map<String,Object>>dispatch(Map<String,Object>event){String from=String.valueOf(event.get("from"));List<String>recipients=routes.get(from);if(recipients==null)throw new PatternException("unsupported_sender");List<Map<String,Object>>out=new ArrayList<>();for(String target:recipients)out.add(Map.of("from",from,"to",target,"message",event.get("message")));return out;}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){SupportMediator mediator=new SupportMediator();List<Map<String,Object>>out=new ArrayList<>();for(Map<String,Object>event:(List<Map<String,Object>>)input.getOrDefault("events",List.of()))out.addAll(mediator.dispatch(event));return Map.of("deliveries",out);}}
